var devices = flow.get('devices', 'file');
if (!devices || devices.length === 0) {
    devices = [
        {id:'1', deviceName:'TR-01', slaveId:8,  ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'2', deviceName:'TR-02', slaveId:9,  ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'3', deviceName:'TR-03', slaveId:10, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'4', deviceName:'TR-04', slaveId:11, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'5', deviceName:'TR-05', slaveId:12, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'6', deviceName:'TR-06', slaveId:13, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'7', deviceName:'TR-07', slaveId:14, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'8', deviceName:'TR-08', slaveId:15, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'9', deviceName:'TR-09', slaveId:16, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'10',deviceName:'TR-10', slaveId:17, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'11',deviceName:'TR-11', slaveId:18, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'12',deviceName:'TR-12', slaveId:19, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'13',deviceName:'TR-13', slaveId:20, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'14',deviceName:'TR-14', slaveId:21, ipAddress:'192.168.2.125', location:'Factory1'},
        {id:'15',deviceName:'TR-15', slaveId:22, ipAddress:'192.168.2.125', location:'Factory1'}
    ];
    flow.set('devices', devices, 'file');
}
return { topic: 'devices', payload: devices };

var topic = msg.topic;
var devices = flow.get('devices', 'file') || [];

if (topic === 'get_devices') {
    return { topic: 'devices', payload: devices };
}
if (topic === 'add_device') {
    devices.push(msg.payload);
    devices.sort(function(a, b) { return parseInt(a.slaveId) - parseInt(b.slaveId); });
    flow.set('devices', devices, 'file');
    return { topic: 'devices', payload: devices };
}
if (topic === 'remove_device') {
    devices = devices.filter(function(d) { return d.id !== msg.payload.id; });
    flow.set('devices', devices, 'file');
    return { topic: 'devices', payload: devices };
}
if (topic === 'update_device') {
    devices = devices.map(function(d) { return d.id === msg.payload.id ? msg.payload : d; });
    flow.set('devices', devices, 'file');
    return { topic: 'devices', payload: devices };
}
if (topic === 'get_email_config') {
    var cfg = flow.get('emailConfig', 'file') || { recipient: '', autoEnabled: true };
    return { topic: 'emailConfig', payload: cfg };
}
if (topic === 'save_email_config') {
    var emailCfg = {
        recipient: String((msg.payload && msg.payload.recipient) || '').trim(),
        autoEnabled: !(msg.payload && msg.payload.autoEnabled === false)
    };
    flow.set('emailConfig', emailCfg, 'file');
    return { topic: 'emailConfig', payload: emailCfg };
}
if (msg.payload && (msg.payload.action === 'send-monthly-report' || msg.payload.action === 'preview-monthly-report')) {
    return msg;
}
return null;

var devices = flow.get('devices', 'file') || [];
if (!devices.length) return null;

var table = flow.get('pollTable') || {};
devices.forEach(function(dev) {
    var slaveId = parseInt(dev.slaveId);
    if (!table[slaveId]) {
        table[slaveId] = {
            deviceName: dev.deviceName,
            vR:'---', vY:'---', vB:'---',
            aR:'---', aY:'---', aB:'---',
            pf:'---', hz:'---', kwh:'---', kvah:'---'
        };
    } else {
        table[slaveId].deviceName = dev.deviceName;
    }
});
flow.set('pollTable', table);

var index = flow.get('pollIndex') || 0;
if (index >= devices.length) index = 0;
var dev = devices[index];
flow.set('pollIndex', (index + 1) % devices.length);

return {
    payload: { fc: 3, unitid: parseInt(dev.slaveId), address: 100, quantity: 62 },
    deviceName: dev.deviceName,
    slaveId: parseInt(dev.slaveId)
};

function rawFloat(first, second) {
    var buf = new ArrayBuffer(4);
    var view = new DataView(buf);
    view.setUint16(0, first, false);
    view.setUint16(2, second, false);
    return view.getFloat32(0, false);
}
function inRange(v, min, max) {
    return Number.isFinite(v) && v >= min && v <= max;
}
function toFloat(hi, lo, min, max) {
    // L&T/Larsen meters commonly return 32-bit floats as low-word, high-word.
    var swapped = rawFloat(lo, hi);
    var normal = rawFloat(hi, lo);
    var chosen = inRange(swapped, min, max) ? swapped : (inRange(normal, min, max) ? normal : NaN);
    return Number.isFinite(chosen) ? Math.round(chosen) : '---';
}
function buildRows(table, devices) {
    return devices.map(function(d) {
        return table[parseInt(d.slaveId)] || {
            deviceName: d.deviceName,
            vR:'---', vY:'---', vB:'---',
            aR:'---', aY:'---', aB:'---',
            pf:'---', hz:'---', kwh:'---', kvah:'---'
        };
    });
}
var regs = Array.isArray(msg.payload) ? msg.payload : (msg.payload && Array.isArray(msg.payload.data) ? msg.payload.data : null);
var table = flow.get('pollTable') || {};
var devices = flow.get('devices', 'file') || [];
if (!regs || regs.length < 62) {
    table[msg.slaveId] = {
        deviceName: msg.deviceName,
        vR:'BAD DATA', vY:'---', vB:'---',
        aR:'---', aY:'---', aB:'---',
        pf:'---', hz:'---', kwh:'---', kvah:'---'
    };
    flow.set('pollTable', table);
    return { topic: 'tableData', payload: buildRows(table, devices), deviceName: msg.deviceName, slaveId: msg.slaveId };
}
var row = {
    deviceName: msg.deviceName,
    vR:   toFloat(regs[42], regs[43], 0, 1000),
    vY:   toFloat(regs[44], regs[45], 0, 1000),
    vB:   toFloat(regs[46], regs[47], 0, 1000),
    aR:   toFloat(regs[50], regs[51], 0, 100000),
    aY:   toFloat(regs[52], regs[53], 0, 100000),
    aB:   toFloat(regs[54], regs[55], 0, 100000),
    pf:   toFloat(regs[16], regs[17], -1, 1),
    hz:   toFloat(regs[56], regs[57], 0, 100),
    kwh:  toFloat(regs[0],  regs[1],  0, 1000000000),
    kvah: toFloat(regs[24], regs[25], 0, 1000000000)
};
table[msg.slaveId] = row;
flow.set('pollTable', table);
return { topic: 'tableData', payload: buildRows(table, devices), deviceName: msg.deviceName, slaveId: msg.slaveId };

if (!Array.isArray(msg.payload)) { return null; }
var rows = msg.payload;
var row = rows.find(function(r) { return r.deviceName === msg.deviceName; });

if (!row || !row.deviceName) { return null; }

var mStatus = (row.offline || row.vR === '---' || row.vR === 'BAD DATA') ? 'OFFLINE' : 'ONLINE';

var key = 'lastEnergyLog_' + msg.slaveId;
var last = flow.get(key) || 0;
var now = Date.now();
if (now - last < 60000) { return null; }
flow.set(key, now);

var dt = new Date(now);
var pad = function(n){ return String(n).padStart(2,'0'); };
var dateTimeDbl = now / 1000 + 2082844800;
var dateStr = pad(dt.getDate()) + '-' + pad(dt.getMonth()+1) + '-' + dt.getFullYear();
var timeStr = pad(dt.getHours()) + ':' + pad(dt.getMinutes()) + ':' + pad(dt.getSeconds());
var devices = flow.get('devices') || flow.get('devices','file') || [];
var dev = devices.find(function(d){ return d.deviceName === row.deviceName; }) || {};
var esc = function(s){ return String(s||'').replace(/'/g,"''"); };
var str = function(v){ return (v===null||v===undefined||v==='---')?'0':String(v); };
var meterId = String(dev.slaveId || msg.slaveId || '0').substring(0, 10);

msg.payload = "INSERT INTO DATA (METER_NUMBER,DATE_TIME_DBL,DATE_STRING,TIME_STRING,TAG_NAME,M_STATUS,V1,V2,V3,AMP1,AMP2,AMP3,PF,HZ,KWH,KVAH,IP_ADD) VALUES ('" +
    esc(meterId) + "'," + dateTimeDbl + ",'" + dateStr + "','" + timeStr + "','" +
    esc(row.deviceName) + "','" + mStatus + "','" + str(row.vR) + "','" + str(row.vY) + "','" + str(row.vB) + "','" +
    str(row.aR) + "','" + str(row.aY) + "','" + str(row.aB) + "','" +
    str(row.pf) + "','" + str(row.hz) + "','" + str(row.kwh) + "','" + str(row.kvah) + "','" +
    esc((dev.ipAddress||'').substring(0,20)) + "')";
return msg;

if (!msg.payload || msg.payload.action !== 'report-query') return null;
var p = msg.payload;
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'report-result', error: 'Both From and To dates are required.' };
    return msg;
}
var interval = parseInt(p.intervalMinutes) || 5;
if ([5, 15, 30, 60].indexOf(interval) === -1) interval = 5;
var macOffset = 2082844800;
var secFrom = Math.floor(new Date(p.dateFrom + 'T00:00:00').getTime() / 1000) + macOffset;
var secTo   = Math.floor(new Date(p.dateTo   + 'T23:59:59').getTime() / 1000) + macOffset;
msg._reportMeta = { dateFrom: p.dateFrom, dateTo: p.dateTo, intervalMinutes: interval };
msg.payload = "WITH interval_rows AS (" +
    " SELECT TAG_NAME, METER_NUMBER, IP_ADD," +
    " FLOOR(DATE_TIME_DBL / (" + (interval * 60) + ".0)) * " + (interval * 60) + ".0 AS interval_sec," +
    " CAST(V1 AS FLOAT) AS V1, CAST(V2 AS FLOAT) AS V2, CAST(V3 AS FLOAT) AS V3," +
    " CAST(AMP1 AS FLOAT) AS AMP1, CAST(AMP2 AS FLOAT) AS AMP2, CAST(AMP3 AS FLOAT) AS AMP3," +
    " CAST(PF AS FLOAT) AS PF, CAST(HZ AS FLOAT) AS HZ," +
    " CAST(KWH AS FLOAT) AS KWH, CAST(KVAH AS FLOAT) AS KVAH" +
    " FROM DATA" +
    " WHERE DATE_TIME_DBL >= " + secFrom + " AND DATE_TIME_DBL <= " + secTo +
    ") " +
    "SELECT TAG_NAME AS device_name, 0 AS slave_id, MAX(IP_ADD) AS ip_address, MAX(METER_NUMBER) AS location," +
    " ROUND(AVG(V1),0) AS v_r, ROUND(AVG(V2),0) AS v_y, ROUND(AVG(V3),0) AS v_b," +
    " ROUND(AVG(AMP1),0) AS a_r, ROUND(AVG(AMP2),0) AS a_y, ROUND(AVG(AMP3),0) AS a_b," +
    " ROUND(AVG(PF),2) AS pf, ROUND(AVG(HZ),2) AS hz," +
    " ROUND(MAX(KWH),2) AS kwh, ROUND(MAX(KVAH),2) AS kvah," +
    " CONVERT(varchar(19), DATEADD(SECOND, CAST(CAST(ROUND(interval_sec,0) AS BIGINT) - 2082844800 + 19800 AS INT), '1970-01-01'), 120) AS logged_at" +
    " FROM interval_rows" +
    " GROUP BY TAG_NAME, interval_sec" +
    " ORDER BY TAG_NAME, interval_sec";
return msg;

var rows = msg.payload || [];
var meta = msg._reportMeta || {};
var num = function(v) {
    if (v === null || v === undefined || v === '') return '';
    var n = parseFloat(v);
    return isNaN(n) ? v : Math.round(n);
};
msg.payload = {
    action: 'report-result',
    rows: rows.map(function(r) {
        return {
            deviceName: r.device_name, slaveId: r.slave_id,
            location: r.location || '', timestamp: r.logged_at,
            vR: num(r.v_r), vY: num(r.v_y), vB: num(r.v_b),
            aR: num(r.a_r), aY: num(r.a_y), aB: num(r.a_b),
            pf: num(r.pf), hz: num(r.hz), kwh: num(r.kwh), kvah: num(r.kvah)
        };
    }),
    meta: meta, count: rows.length
};
return msg;

