func:
if (!msg.payload || (msg.payload.action !== 'send-monthly-report' && msg.payload.action !== 'preview-monthly-report')) return null;
var p = msg.payload;
var year  = parseInt(p.year);
var month = parseInt(p.month);
var pad   = function(n) { return String(n).padStart(2,'0'); };
var endMonth = month === 12 ? 1 : month + 1;
var endYear  = month === 12 ? year + 1 : year;
var macOffset = 2082844800;
var secStart = Math.floor(new Date(year, month - 1, 1).getTime() / 1000) + macOffset;
var secEnd   = Math.floor(new Date(endYear, endMonth - 1, 1).getTime() / 1000) + macOffset;
var lastDay  = new Date(endYear, endMonth - 1, 0);
msg._emailMeta = {
    action: p.action,
    year: year,
    month: month,
    email: p.email,
    automatic: !!p.automatic,
    dateFrom: year + '-' + pad(month) + '-01',
    dateTo: lastDay.getFullYear() + '-' + pad(lastDay.getMonth() + 1) + '-' + pad(lastDay.getDate())
};
msg.payload = "SELECT TAG_NAME AS device_name, MAX(CAST(METER_NUMBER AS INT)) AS slave_id, " +
    "MAX(CAST(KWH AS FLOAT)) AS max_kwh, MIN(CAST(KWH AS FLOAT)) AS min_kwh, " +
    "MAX(CAST(KVAH AS FLOAT)) AS max_kvah, MIN(CAST(KVAH AS FLOAT)) AS min_kvah " +
    "FROM DATA " +
    "WHERE DATE_TIME_DBL >= " + secStart + " AND DATE_TIME_DBL < " + secEnd + " " +
    "AND CAST(METER_NUMBER AS INT) BETWEEN 8 AND 23 " +
    "GROUP BY TAG_NAME " +
    "ORDER BY MAX(CAST(METER_NUMBER AS INT))";
return msg;

var rows = msg.payload || [];
var meta = msg._emailMeta || {};
var monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
var monthLabel = monthNames[(meta.month || 1) - 1] + ' ' + (meta.year || '');

if (!rows.length) {
    if (meta.action === 'preview-monthly-report') {
        return [null, { topic: 'reportPreview', payload: { error: 'No energy data found for ' + monthLabel + '.' } }];
    }
    msg.payload = { action: 'email-result', error: 'No energy data found for ' + monthLabel + '.' };
    return [null, msg];
}

var fmt = function(n) {
    n = parseFloat(n) || 0;
    return String(Math.round(n));
};
var esc = function(s) {
    return String(s == null ? '' : s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
};

var deviceRows = rows.map(function(r) {
    var kwh = Math.max(0, (parseFloat(r.max_kwh) || 0) - (parseFloat(r.min_kwh) || 0));
    var kvah = Math.max(0, (parseFloat(r.max_kvah) || 0) - (parseFloat(r.min_kvah) || 0));
    return {
        deviceName: r.device_name,
        slaveId: parseInt(r.slave_id) || 0,
        kwh: kwh,
        kvah: kvah
    };
}).sort(function(a, b) { return a.slaveId - b.slaveId; });

var totalKwh = deviceRows.reduce(function(sum, r) { return sum + r.kwh; }, 0);
var totalKvah = deviceRows.reduce(function(sum, r) { return sum + r.kvah; }, 0);
var now = new Date();
var pad = function(n) { return String(n).padStart(2, '0'); };
var printedAt = pad(now.getDate()) + '-' + pad(now.getMonth() + 1) + '-' + now.getFullYear() +
    ' ' + pad(now.getHours()) + ':' + pad(now.getMinutes());

var css = [
    '*{box-sizing:border-box;margin:0;padding:0;}',
    'body{font-family:Arial,sans-serif;font-size:10px;color:#0F172A;background:#fff;}',
    '.page{padding:18px 22px;}',
    '.co-header{display:flex;justify-content:space-between;align-items:center;padding-bottom:8px;border-bottom:2.5px solid #0F172A;margin-bottom:6px;}',
    '.co-name{font-size:13px;font-weight:900;color:#C41E1E;margin-bottom:2px;}',
    '.co-addr{font-size:9px;color:#475569;line-height:1.7;}',
    '.rpt-title{text-align:center;font-size:12px;font-weight:800;letter-spacing:1.5px;text-decoration:underline;margin:7px 0;}',
    '.meta{display:flex;justify-content:space-between;font-size:10px;margin-bottom:8px;border-bottom:1px solid #CBD5E1;padding-bottom:6px;}',
    'table{width:100%;border-collapse:collapse;}',
    'th{padding:7px 5px;background:#1E293B;color:#fff;font-size:8.5px;font-weight:700;text-align:center;border:1px solid #334155;text-transform:uppercase;white-space:nowrap;}',
    'td{padding:6px 5px;font-size:9.5px;text-align:center;border:1px solid #CBD5E1;}',
    '.dev{text-align:center;font-weight:700;}',
    '.num{text-align:center;font-weight:700;}',
    '.total td{background:#DBEAFE;font-size:10px;font-weight:900;}',
    '.footer{margin-top:12px;padding-top:8px;border-top:2px solid #0F172A;}',
    '.sig-row{display:flex;justify-content:space-between;font-size:9px;font-weight:700;margin-bottom:6px;}',
    '.sig-line{margin-top:20px;border-top:1px solid #0F172A;padding-top:2px;font-size:8.5px;font-weight:400;width:150px;}',
    '.footer-print{text-align:center;font-size:9px;font-weight:700;border-top:1px solid #CBD5E1;padding-top:5px;margin-top:3px;}'
].join('');

var bodyRows = deviceRows.map(function(r, i) {
    var bg = i % 2 === 0 ? '#FFFFFF' : '#F5F7FA';
    return '<tr style="background:' + bg + '">' +
        '<td>' + (i + 1) + '</td>' +
        '<td>' + r.slaveId + '</td>' +
        '<td class="dev">' + esc(r.deviceName) + '</td>' +
        '<td class="num">' + fmt(r.kwh) + '</td>' +
        '<td class="num">' + fmt(r.kvah) + '</td>' +
        '</tr>';
}).join('');

var h = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Monthly Energy Report</title><style>' + css + '</style></head>';
h += '<body><div class="page">';
h += '<div class="co-header"><div><div class="co-name">JETPACE TECHNOLOGIES</div><div class="co-addr">Tarsali, Vadodara - 390009<br>Jetpace Energy EMS</div></div></div>';
h += '<div class="rpt-title">MONTHLY ENERGY CONSUMPTION REPORT</div>';
h += '<div class="meta"><div>Equipment: <b>Jetpace Energy EMS</b></div><div>MONTH: <b>' + esc(monthLabel) + '</b> &nbsp;|&nbsp; PERIOD: <b>' + esc(meta.dateFrom || '') + '</b> to <b>' + esc(meta.dateTo || '') + '</b></div></div>';
h += '<table><thead><tr><th>SR.<br>NO</th><th>SLAVE<br>ID</th><th>DEVICE<br>NAME</th><th>MONTHLY<br>KWH</th><th>MONTHLY<br>KVAH</th></tr></thead><tbody>' + bodyRows;
h += '<tr class="total"><td colspan="3">TOTAL MONTHLY CONSUMPTION</td><td class="num">' + fmt(totalKwh) + '</td><td class="num">' + fmt(totalKvah) + '</td></tr>';
h += '</tbody></table>';
h += '<div class="footer"><div class="sig-row"><div>Check by<div class="sig-line">Sign &amp; Date :- _______________</div></div><div style="align-self:flex-end;font-weight:400;">page 1 of 1</div><div style="text-align:right;">Reviewed by<div class="sig-line" style="margin-left:auto;">Sign &amp; Date :- _______________</div></div></div>';
h += '<div class="footer-print">Printed Date Time: ' + printedAt + '</div></div>';
h += '</div></body></html>';

if (meta.action === 'preview-monthly-report') {
    var printCss = '@page{size:A4 landscape;margin:10mm;}@media print{.no-print{display:none!important;}body{-webkit-print-color-adjust:exact;print-color-adjust:exact;}}';
    var toolbar = '<div class="no-print" style="padding:8px 16px;background:#1e293b;display:flex;justify-content:space-between;align-items:center;">'
        + '<span style="color:#94a3b8;font-size:10px;font-weight:700;letter-spacing:1px;">REPORT PREVIEW – ' + esc(monthLabel) + '</span>'
        + '<button onclick="window.print()" style="padding:6px 18px;background:#0d9488;color:#fff;border:none;border-radius:3px;cursor:pointer;font-size:11px;font-weight:700;">Download as PDF</button>'
        + '</div>';
    var previewH = h.replace('</style></head>', printCss + '</style></head>').replace('<body>', '<body>' + toolbar);
    return [null, { topic: 'reportPreview', payload: { html: previewH } }];
}

var emailMsg = {
    to: meta.email,
    topic: 'Monthly Energy Consumption Report - ' + monthLabel,
    payload: h,
    _msgid: msg._msgid
};

msg.payload = {
    action: 'email-result',
    success: true,
    monthLabel: monthLabel,
    automatic: !!meta.automatic,
    count: deviceRows.length,
    totalKwh: fmt(totalKwh),
    totalKvah: fmt(totalKvah)
};
return [emailMsg, msg];

function buildRows(table, devices) {
    return devices.map(function(d) {
        return table[parseInt(d.slaveId)] || {
            deviceName: d.deviceName,
            vR:'---', vY:'---', vB:'---',
            aR:'---', aY:'---', aB:'---',
            pf:'---', hz:'---', kwh:'---', kvah:'---'
        };
    });
}
var table = flow.get('pollTable') || {};
var devices = flow.get('devices', 'file') || [];
var slaveId = parseInt(msg.slaveId || (msg.modbusRequest && msg.modbusRequest.unitid));
if (!slaveId) return null;
var dev = devices.find(function(d) { return parseInt(d.slaveId) === slaveId; }) || {};
table[slaveId] = {
    deviceName: msg.deviceName || dev.deviceName || ('Slave ' + slaveId),
    vR:   'OFFLINE',
    vY:   '---',
    vB:   '---',
    aR:   '---',
    aY:   '---',
    aB:   '---',
    pf:   '---',
    hz:   '---',
    kwh:  '---',
    kvah: '---',
    offline: true
};
flow.set('pollTable', table);
return { topic: 'tableData', payload: buildRows(table, devices) };

var cfg = flow.get('emailConfig', 'file') || {};
if (cfg.autoEnabled === false) return null;
if (!cfg.recipient || !String(cfg.recipient).includes('@')) return null;

var now = new Date();
var prev = new Date(now.getFullYear(), now.getMonth() - 1, 1);
msg.payload = {
    action: 'send-monthly-report',
    year: prev.getFullYear(),
    month: prev.getMonth() + 1,
    email: String(cfg.recipient).trim(),
    automatic: true
};
return msg;
